        /*bill.getCurPrevMonthBill*/
SELECT (
              -- 현재월 AWS 데이터
              SELECT COALESCE(SUM(ms.total_cost), 0)
                FROM monthly_summation ms
               WHERE ms.year_month = #{curYearMonth}

                 AND ms.csp IN

                     #{selectedCsp}


                 AND ms.project_cd IN

                     #{selectedProject}

              ) + (
              -- 현재월 NCP VM 데이터 (VM별 최신 누적 금액만 반영)
              SELECT COALESCE(SUM(nvd_latest.demand_amount), 0) / ${krwPerUsd}
                FROM (
                    SELECT n1.instance_no, n1.demand_amount
                    FROM ncp_cost_vm_month n1
                    INNER JOIN (
                        SELECT instance_no, MAX(id) AS latest_id
                        FROM ncp_cost_vm_month
                        WHERE demand_month = #{curYearMonth}
                        GROUP BY instance_no
                    ) n2
                    ON n1.instance_no = n2.instance_no
                    AND n1.id = n2.latest_id
                ) nvd_latest
          INNER JOIN servicegroup_meta sm
               ON nvd_latest.instance_no COLLATE utf8mb4_unicode_ci = sm.csp_instanceid COLLATE utf8mb4_unicode_ci
              AND sm.csp_type = 'NCP'
            WHERE 1=1

                 AND sm.service_cd IN

                     #{selectedProject}



                 AND 1=0

              ) + (
              -- 현재월 Azure VM 데이터 (조인 후 계산)
              SELECT COALESCE(SUM(acvd.pre_tax_cost), 0) / ${krwPerUsd}
                FROM azure_cost_vm_daily acvd
               INNER JOIN servicegroup_meta sm
                  ON acvd.vm_id COLLATE utf8mb4_unicode_ci = sm.vm_uid COLLATE utf8mb4_unicode_ci
                 AND sm.csp_type = 'AZURE'

                 AND sm.service_cd IN

                     #{selectedProject}


               WHERE DATE_FORMAT(acvd.usage_date, '%Y%m') = #{curYearMonth}

                 AND 1=0

              ) AS curMonthBill,

       (
              -- 이전월 AWS 데이터
              SELECT COALESCE(SUM(ms.total_cost), 0)
                FROM monthly_summation ms
               WHERE ms.year_month = #{prevYearMonth}

                 AND ms.csp IN

                     #{selectedCsp}


                 AND ms.project_cd IN

                     #{selectedProject}

              ) + (
              -- 이전월 NCP VM 데이터 (VM별 최신 누적 금액만 반영)
                SELECT COALESCE(SUM(nvd_latest.demand_amount), 0) / ${krwPerUsd}
                  FROM (
                    SELECT n1.instance_no, n1.demand_amount
                    FROM ncp_cost_vm_month n1
                    INNER JOIN (
                        SELECT instance_no, MAX(id) AS latest_id
                        FROM ncp_cost_vm_month
                        WHERE demand_month = #{prevYearMonth}
                        GROUP BY instance_no
                    ) n2
                    ON n1.instance_no = n2.instance_no
                    AND n1.id = n2.latest_id
                ) nvd_latest
            INNER JOIN servicegroup_meta sm
                    ON nvd_latest.instance_no COLLATE utf8mb4_unicode_ci = sm.csp_instanceid COLLATE utf8mb4_unicode_ci
                   AND sm.csp_type = 'NCP'
                 WHERE 1=1

                   AND sm.service_cd IN

                    #{selectedProject}



                AND 1=0

              ) + (
              -- 이전월 Azure VM 데이터 (조인 후 계산)
              SELECT COALESCE(SUM(acvd.pre_tax_cost), 0) / ${krwPerUsd}
                FROM azure_cost_vm_daily acvd
               INNER JOIN servicegroup_meta sm
                  ON acvd.vm_id COLLATE utf8mb4_unicode_ci = sm.vm_uid COLLATE utf8mb4_unicode_ci
                 AND sm.csp_type = 'AZURE'

                 AND sm.service_cd IN

                     #{selectedProject}


               WHERE DATE_FORMAT(acvd.usage_date, '%Y%m') = #{prevYearMonth}

                 AND 1=0

              ) AS prevMonthBill

/*bill.getMonthBill*/ SELECT ym.`year_month` , SUBSTRING(ym.`year_month`, 1, 4) AS `year` , SUBSTRING(ym.`year_month`, 5, 2) AS `month` , COALESCE(SUM(all_data.total_cost), 0) AS bill FROM (
SELECT #{prevMonth} COLLATE utf8mb4_unicode_ci AS `year_month`
) AS ym LEFT JOIN ( -- AWS 데이터 SELECT ms.`year_month` COLLATE utf8mb4_unicode_ci AS `year_month` , SUM(ms.total_cost) AS total_cost FROM monthly_summation ms WHERE ms.project_cd IN
#{selectedProject}
AND ms.csp IN
#{selectedCsp}
AND ms.`year_month` IN
#{prevMonth}
GROUP BY ms.`year_month`
UNION ALL
-- NCP VM 데이터 (VM별 월별 최신 누적 금액만 반영) SELECT nvd_latest.demand_month COLLATE utf8mb4_unicode_ci AS `year_month`, SUM(nvd_latest.demand_amount) / ${krwPerUsd} AS total_cost FROM ( SELECT n1.demand_month, n1.instance_no, n1.demand_amount FROM ncp_cost_vm_month n1 INNER JOIN ( SELECT demand_month, instance_no, MAX(id) AS latest_id FROM ncp_cost_vm_month WHERE demand_month IN
#{prevMonth}
GROUP BY demand_month, instance_no ) n2 ON n1.demand_month = n2.demand_month AND n1.instance_no = n2.instance_no AND n1.id = n2.latest_id ) nvd_latest INNER JOIN servicegroup_meta sm ON nvd_latest.instance_no COLLATE utf8mb4_unicode_ci = sm.csp_instanceid COLLATE utf8mb4_unicode_ci AND sm.csp_type = 'NCP'
AND sm.service_cd IN
#{selectedProject}
AND 1=0
GROUP BY nvd_latest.demand_month
UNION ALL
-- Azure VM 데이터 (servicegroup_meta 조인 후 필터링) SELECT DATE_FORMAT(acvd.usage_date, '%Y%m') COLLATE utf8mb4_unicode_ci AS `year_month` , SUM(acvd.pre_tax_cost) / ${krwPerUsd} AS total_cost FROM azure_cost_vm_daily acvd INNER JOIN servicegroup_meta sm ON acvd.vm_id COLLATE utf8mb4_unicode_ci = sm.vm_uid COLLATE utf8mb4_unicode_ci AND sm.csp_type = 'AZURE'
AND sm.service_cd IN
#{selectedProject}
WHERE DATE_FORMAT(acvd.usage_date, '%Y%m') IN
#{prevMonth}
AND 1=0
GROUP BY DATE_FORMAT(acvd.usage_date, '%Y%m') ) AS all_data ON ym.`year_month` = all_data.`year_month` GROUP BY ym.`year_month` ORDER BY ym.`year_month` DESC

SELECT service_name AS resourceNm , total_cost AS bill , csp FROM (
SELECT co.lineitem_productcode COLLATE utf8mb4_unicode_ci AS service_name , COALESCE(SUM(co.lineitem_unblendedcost), 0) AS total_cost , 'AWS' COLLATE utf8mb4_unicode_ci AS csp FROM tbl_table_billing_detail_${year_month} co LEFT JOIN servicegroup_meta sm ON co.lineitem_resourceid = sm.csp_instanceid WHERE sm.service_cd IN
#{selectedProject}
AND co.lineitem_usagestartdate >= #{curMonthStartDate} AND co.lineitem_usageenddate <= #{curMonthEndDate}
GROUP BY co.lineitem_productcode
UNION ALL
SELECT CASE WHEN sm.service_type = 'VM' THEN 'Virtual Machine' ELSE sm.service_type END COLLATE utf8mb4_unicode_ci AS service_name , COALESCE(SUM(acvd.pre_tax_cost), 0) / ${krwPerUsd} AS total_cost , 'AZURE' COLLATE utf8mb4_unicode_ci AS csp FROM azure_cost_vm_daily acvd INNER JOIN servicegroup_meta sm ON acvd.resource_id COLLATE utf8mb4_unicode_ci = sm.csp_instanceid COLLATE utf8mb4_unicode_ci AND sm.csp_type = 'AZURE' WHERE DATE_FORMAT(acvd.usage_date, '%Y%m') = #{year_month}
AND sm.service_cd IN
#{selectedProject}
GROUP BY CASE WHEN sm.service_type = 'VM' THEN 'Virtual Machine' ELSE sm.service_type END
UNION ALL
SELECT CASE WHEN sm.service_type = 'VM' THEN 'Server' ELSE sm.service_type END COLLATE utf8mb4_unicode_ci AS service_name , COALESCE(SUM(vm_latest.demand_amount), 0) / ${krwPerUsd} AS total_cost , 'NCP' COLLATE utf8mb4_unicode_ci AS csp FROM ( SELECT n1.instance_no, n1.demand_amount FROM ncp_cost_vm_month n1 INNER JOIN ( SELECT instance_no, MAX(id) AS latest_id FROM ncp_cost_vm_month WHERE demand_month = #{year_month} GROUP BY instance_no ) n2 ON n1.instance_no = n2.instance_no AND n1.id = n2.latest_id ) vm_latest INNER JOIN servicegroup_meta sm ON vm_latest.instance_no COLLATE utf8mb4_unicode_ci = sm.csp_instanceid COLLATE utf8mb4_unicode_ci AND sm.csp_type = 'NCP' WHERE 1=1
AND sm.service_cd IN
#{selectedProject}
GROUP BY CASE WHEN sm.service_type = 'VM' THEN 'Server' ELSE sm.service_type END UNION ALL
SELECT raw.service_description COLLATE utf8mb4_unicode_ci AS service_name , COALESCE(SUM(raw.cost), 0) / ${krwPerUsd} AS total_cost , 'GCP' COLLATE utf8mb4_unicode_ci AS csp FROM gcp_billing_raw raw LEFT JOIN servicegroup_meta sm ON sm.csp_type = 'GCP' AND sm.csp_instanceid COLLATE utf8mb4_uca1400_ai_ci = raw.csp_instanceid WHERE raw.invoice_month = #{year_month}
AND COALESCE(sm.service_cd COLLATE utf8mb4_uca1400_ai_ci, raw.service_cd, 'undefined') IN
#{selectedProject}
GROUP BY raw.service_description ) AS all_services WHERE total_cost > 0 ORDER BY total_cost DESC LIMIT 5

SELECT childProductCode , SUM(bill) AS bill , SUM(unit) AS unit , csp FROM ( -- AWS VM 데이터 (service_type = 'VM') SELECT COALESCE(SUM(co.lineitem_unblendedcost), 0) AS bill , 'VM' COLLATE utf8mb4_unicode_ci AS childProductCode , COUNT(DISTINCT co.lineitem_resourceid) AS unit , 'AWS' COLLATE utf8mb4_unicode_ci AS csp FROM tbl_table_billing_detail_${year_month} co INNER JOIN servicegroup_meta sm ON co.lineitem_resourceid COLLATE utf8mb4_unicode_ci = sm.csp_instanceid COLLATE utf8mb4_unicode_ci AND sm.csp_type = 'AWS' AND sm.service_type = 'VM' WHERE 1=1
AND sm.service_cd IN
#{selectedProject}
AND co.lineitem_usagestartdate >= #{curMonthStartDate} AND co.lineitem_usageenddate < #{curMonthEndDate}
AND 1=0
UNION ALL
-- AWS K8S 데이터 (service_type = 'K8S') SELECT COALESCE(SUM(co.lineitem_unblendedcost), 0) AS bill , 'K8S' COLLATE utf8mb4_unicode_ci AS childProductCode , COUNT(DISTINCT co.lineitem_resourceid) AS unit , 'AWS' COLLATE utf8mb4_unicode_ci AS csp FROM tbl_table_billing_detail_${year_month} co INNER JOIN servicegroup_meta sm ON co.lineitem_resourceid COLLATE utf8mb4_unicode_ci = sm.csp_instanceid COLLATE utf8mb4_unicode_ci AND sm.csp_type = 'AWS' AND sm.service_type = 'K8S' WHERE 1=1
AND sm.service_cd IN
#{selectedProject}
AND co.lineitem_usagestartdate >= #{curMonthStartDate} AND co.lineitem_usageenddate < #{curMonthEndDate}
AND 1=0
UNION ALL
-- AWS Others 데이터 (service_type이 VM/K8S가 아닌 것, 메타에 등록된 리소스만) SELECT COALESCE(SUM(co.lineitem_unblendedcost), 0) AS bill , 'Others' COLLATE utf8mb4_unicode_ci AS childProductCode , COUNT(DISTINCT co.lineitem_resourceid) AS unit , 'AWS' COLLATE utf8mb4_unicode_ci AS csp FROM tbl_table_billing_detail_${year_month} co INNER JOIN servicegroup_meta sm ON co.lineitem_resourceid COLLATE utf8mb4_unicode_ci = sm.csp_instanceid COLLATE utf8mb4_unicode_ci AND sm.csp_type = 'AWS' AND sm.service_type NOT IN ('VM', 'K8S') WHERE 1=1
AND sm.service_cd IN
#{selectedProject}
AND co.lineitem_usagestartdate >= #{curMonthStartDate} AND co.lineitem_usageenddate < #{curMonthEndDate}
AND 1=0
UNION ALL
-- Azure VM 데이터 (service_type = 'VM') SELECT COALESCE(SUM(acvd.pre_tax_cost), 0) / ${krwPerUsd} AS bill , 'VM' COLLATE utf8mb4_unicode_ci AS childProductCode , COUNT(DISTINCT acvd.resource_id) AS unit , 'AZURE' COLLATE utf8mb4_unicode_ci AS csp FROM azure_cost_vm_daily acvd INNER JOIN servicegroup_meta sm ON acvd.resource_id COLLATE utf8mb4_unicode_ci = sm.csp_instanceid COLLATE utf8mb4_unicode_ci AND sm.csp_type = 'AZURE' AND sm.service_type = 'VM' WHERE DATE_FORMAT(acvd.usage_date, '%Y%m') = #{year_month}
AND sm.service_cd IN
#{selectedProject}
AND 1=0
-- TODO: Azure K8S 데이터 추가 필요 -- TODO: Azure Others 데이터 추가 필요
UNION ALL
-- NCP VM 데이터 (service_type = 'VM') SELECT COALESCE(SUM(ncvd.daily_charge_amount), 0) / ${krwPerUsd} AS bill , 'VM' COLLATE utf8mb4_unicode_ci AS childProductCode , COUNT(DISTINCT ncvd.instance_no) AS unit , 'NCP' COLLATE utf8mb4_unicode_ci AS csp FROM ncp_cost_vm_daily ncvd INNER JOIN servicegroup_meta sm ON ncvd.instance_no COLLATE utf8mb4_unicode_ci = sm.csp_instanceid COLLATE utf8mb4_unicode_ci AND sm.csp_type = 'NCP' AND sm.service_type = 'VM' WHERE DATE_FORMAT(ncvd.target_date, '%Y%m') = #{year_month}
AND sm.service_cd IN
#{selectedProject}
AND 1=0
-- TODO: NCP K8S 데이터 추가 필요 -- TODO: NCP Others 데이터 추가 필요
UNION ALL
-- GCP VM (servicegroup_meta.service_type = 'VM', invoice_month 기준, KRW→USD) SELECT COALESCE(SUM(raw.cost), 0) / ${krwPerUsd} AS bill , 'VM' COLLATE utf8mb4_unicode_ci AS childProductCode , COUNT(DISTINCT raw.csp_instanceid) AS unit , 'GCP' COLLATE utf8mb4_unicode_ci AS csp FROM gcp_billing_raw raw INNER JOIN servicegroup_meta sm ON sm.csp_type = 'GCP' AND sm.service_type = 'VM' AND sm.csp_instanceid COLLATE utf8mb4_uca1400_ai_ci = raw.csp_instanceid WHERE raw.invoice_month = #{year_month}
AND sm.service_cd COLLATE utf8mb4_uca1400_ai_ci IN
#{selectedProject}
AND 1=0
UNION ALL
-- GCP Others (VM 으로 매칭되지 않는 나머지 — 공통/네트워크/라벨없음 포함) SELECT COALESCE(SUM(raw.cost), 0) / ${krwPerUsd} AS bill , 'Others' COLLATE utf8mb4_unicode_ci AS childProductCode , COUNT(DISTINCT raw.csp_instanceid) AS unit , 'GCP' COLLATE utf8mb4_unicode_ci AS csp FROM gcp_billing_raw raw LEFT JOIN servicegroup_meta sm ON sm.csp_type = 'GCP' AND sm.service_type = 'VM' AND sm.csp_instanceid COLLATE utf8mb4_uca1400_ai_ci = raw.csp_instanceid WHERE raw.invoice_month = #{year_month} AND sm.csp_instanceid IS NULL
AND COALESCE(sm.service_cd COLLATE utf8mb4_uca1400_ai_ci, raw.service_cd, 'undefined') IN
#{selectedProject}
AND 1=0
) subquery WHERE bill > 0 OR childProductCode = 'Others' GROUP BY childProductCode, csp ORDER BY bill DESC

SELECT csp, SUM(cost) AS cost FROM (
SELECT 'AWS' AS csp, COALESCE(SUM(co.lineitem_unblendedcost), 0) AS cost FROM tbl_table_billing_detail_${year_month} co INNER JOIN servicegroup_meta sm ON co.lineitem_resourceid COLLATE utf8mb4_unicode_ci = sm.csp_instanceid COLLATE utf8mb4_unicode_ci AND sm.csp_type = 'AWS'
AND sm.service_cd IN
#{selectedProject}
AND co.lineitem_usagestartdate >= #{curMonthStartDate} AND co.lineitem_usageenddate < #{curMonthEndDate}
UNION ALL
SELECT 'NCP' AS csp, COALESCE(SUM(nvd_latest.demand_amount), 0) / ${krwPerUsd} AS cost FROM ( SELECT n1.instance_no, n1.demand_amount FROM ncp_cost_vm_month n1 INNER JOIN ( SELECT instance_no, MAX(id) AS latest_id FROM ncp_cost_vm_month WHERE demand_month = #{year_month} GROUP BY instance_no ) n2 ON n1.instance_no = n2.instance_no AND n1.id = n2.latest_id ) nvd_latest INNER JOIN servicegroup_meta sm ON nvd_latest.instance_no COLLATE utf8mb4_unicode_ci = sm.csp_instanceid COLLATE utf8mb4_unicode_ci AND sm.csp_type = 'NCP'
AND sm.service_cd IN
#{selectedProject}
UNION ALL
SELECT 'AZURE' AS csp, COALESCE(SUM(acvd.pre_tax_cost), 0) / ${krwPerUsd} AS cost FROM azure_cost_vm_daily acvd INNER JOIN servicegroup_meta sm ON acvd.vm_id COLLATE utf8mb4_unicode_ci = sm.vm_uid COLLATE utf8mb4_unicode_ci AND sm.csp_type = 'AZURE'
AND sm.service_cd IN
#{selectedProject}
WHERE DATE_FORMAT(acvd.usage_date, '%Y%m') = #{year_month}
UNION ALL
SELECT 'GCP' AS csp, COALESCE(SUM(ms.total_cost), 0) AS cost FROM monthly_summation ms WHERE ms.csp = 'GCP' AND ms.`year_month` = #{year_month}
AND ms.project_cd IN
#{selectedProject}
UNION ALL
SELECT 'GCP' AS csp, COALESCE(SUM(raw.cost), 0) / ${krwPerUsd} AS cost FROM gcp_billing_raw raw LEFT JOIN servicegroup_meta sm ON sm.csp_type = 'GCP' AND sm.csp_instanceid COLLATE utf8mb4_uca1400_ai_ci = raw.csp_instanceid WHERE raw.invoice_month = #{year_month}
AND COALESCE(sm.service_cd COLLATE utf8mb4_uca1400_ai_ci, raw.service_cd, 'undefined') IN
#{selectedProject}
) AS combined_costs GROUP BY csp
